def _adapt_for_profile(topics: List[Dict], profile: Dict) -> List[Dict]:
    """
    Algorithmically adapt topic list based on learner profile.
    This is the CORE INTELLIGENCE that the model learns to replicate.
    """
    adapted = []
    focus_minutes = _parse_focus_duration(profile["focus_duration"])
    velocity = profile.get("learning_velocity", "medium")
    forgetting_rate = profile.get("forgetting_rate", 0.3)
    
    for i, t in enumerate(topics):
        hours = t["hours"]
        
        # Rule 1: Micro-learners need smaller chunks
        if focus_minutes <= 25:
            hours = min(hours, 1.5)
        
        # Rule 2: Slow learners get more time
        if velocity == "slow":
            hours = round(hours * 1.3, 1)
        elif velocity == "fast":
            hours = round(hours * 0.8, 1)
        
        # Rule 3: High forgetting rate → add more revision checkpoints
        # (we handle this by reducing hours per topic to leave room for revision)
        if forgetting_rate > 0.35:
            hours = round(hours * 0.9, 1)
        
        adapted.append({
            "name": t["name"],
            "difficulty": t["difficulty"],
            "estimated_hours": max(0.5, hours),  # minimum 30 min
            "key_concepts": t["concepts"],
            "prerequisites": t["prereqs"],
            "sort_order": i + 1,
        })
    
    return adapted


def _parse_focus_duration(focus_str: str) -> int:
    """Extract minutes from focus duration string."""
    if "15" in focus_str:
        return 15
    elif "25" in focus_str:
        return 25
    elif "50" in focus_str:
        return 50
    elif "90" in focus_str:
        return 90
    return 50


def generate_curriculum(profile: Dict[str, Any], subject: str) -> Optional[Dict[str, Any]]:
    """
    Generate a complete, personalized curriculum WITHOUT any API call.
    Uses curated domain knowledge + algorithmic adaptation rules.
    """
    if subject not in DOMAIN_KNOWLEDGE:
        return None
    
    level = profile.get("level", "Beginner").lower()
    if level not in DOMAIN_KNOWLEDGE[subject]:
        level = "beginner"
    
    base_topics = DOMAIN_KNOWLEDGE[subject][level]
    adapted_topics = _adapt_for_profile(base_topics, profile)
    
    return {
        "user_profile": profile["summary"],
        "subject": subject,
        "topics": adapted_topics,
    }


